const telemetry = $fromAI('query');
const issues = [];

// Validate generation
if (telemetry.generation) {
  if (telemetry.generation.output_mw < 0 || telemetry.generation.output_mw > 1000) {
    issues.push("Generation output out of range");
  }
  if (telemetry.generation.frequency_hz < 59.5 || telemetry.generation.frequency_hz > 60.5) {
    issues.push("Frequency deviation detected");
  }
}

// Validate load
if (telemetry.load) {
  if (telemetry.load.consumption_mw < 0 || telemetry.load.consumption_mw > 800) {
    issues.push("Load consumption out of range");
  }
}

// Validate storage
if (telemetry.storage) {
  if (telemetry.storage.charge_percent < 0 || telemetry.storage.charge_percent > 100) {
    issues.push("Storage charge level invalid");
  }
}

return JSON.stringify({ validation_issues: issues, is_valid: issues.length === 0 });
